mapper.select:
SELECT fd.id, fd.url, fd.size, fd.filename, fd.original_filename, fd.bucket_name, fd.object_name, fd.base_path, fd.path, fd.ext, fd.content_type, fd.platform, fd.hash_info, fd.upload_id, fd.upload_status, fd.user_id, fd.knowledge_base_id, fd.create_time, kb.name AS knowledge_base_name FROM file_detail fd LEFT JOIN knowledge_base kb ON fd.knowledge_base_id = kb.id
AND fd.original_filename LIKE CONCAT('%', #{filename}, '%')
AND fd.hash_info = #{hashInfo}
AND fd.upload_status = #{uploadStatus}
AND fd.user_id = #{userId}
ORDER BY fd.create_time DESC
